Custom Request.code:
// Make an arbitrary HTTP request.
// state.data is set to the parsed response body.
request('POST', 'https://api.example.org/v1/things', {
  // JSON body (sent as application/json by default).
  body: { name: $.data.name, amount: $.data.amount },
  // Extra headers.
  headers: { 'X-Trace-Id': $.run.id },
  // Querystring parameters.
  query: { ref: $.data.ref },
});

PUT Request.code:
// Send a PUT request with a JSON body.
put('https://api.example.org/v1/things/123', $.data.payload, {
  headers: { 'X-Trace-Id': $.run.id },
});

POST Request.code:
// Send a POST request with a JSON body.
post('https://api.example.org/v1/things', $.data.payload, {
  headers: { 'X-Trace-Id': $.run.id },
});

GET Request.code:
// Send a GET request.
get('https://api.example.org/v1/things', {
  query: { limit: 10, status: 'active' },
});
